package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrint() throws IOException {
        // Given
        StringWriter out = new StringWriter();
        CharSequence value = "test";
        boolean newRecord = true;

        // When
        csvFormat.print(value, out, newRecord);

        // Then
        assertEquals(value.toString(), out.toString());
    }

    @Test
    public void testPrintWithObject() throws IOException {
        // Given
        StringWriter out = new StringWriter();
        Object object = 123;
        CharSequence value = "456";
        boolean newRecord = true;

        // When
        csvFormat.print(value, out, newRecord);

        // Then
        assertEquals("\"456\"", out.toString());
    }

    @Test
    public void testPrintAndEscape() throws Exception {
        // Given
        StringWriter out = new StringWriter();
        CharSequence value = "te,st";

        // When
        Method method = CSVFormat.class.getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class, Appendable.class);
        method.setAccessible(true);
        method.invoke(csvFormat, value, 0, value.length(), out);

        // Then
        assertEquals("te\\,st", out.toString());
    }

    @Test
    public void testPrintAndQuote() throws Exception {
        // Given
        StringWriter out = new StringWriter();
        Object object = 123;
        CharSequence value = "456";
        boolean newRecord = true;

        // When
        Method method = CSVFormat.class.getDeclaredMethod("printAndQuote", Object.class, CharSequence.class, int.class, int.class, Appendable.class, boolean.class);
        method.setAccessible(true);
        method.invoke(csvFormat, object, value, 0, value.length(), out, newRecord);

        // Then
        assertEquals("\"456\"", out.toString());
    }
}
